typedef struct _USB_DEVICE_DESCRIPTOR {   UCHAR  bLength;
UCHAR  bDescriptorType;   USHORT bcdUSB;
UCHAR  bDeviceClass;
UCHAR  bDeviceSubClass;   UCHAR  bDeviceProtocol;   UCHAR  bMaxPacketSize0;
USHORT idVendor;   USHORT idProduct;   USHORT bcdDevice;
UCHAR  iManufacturer;   UCHAR  iProduct;
UCHAR  iSerialNumber;
UCHAR  bNumConfigurations;
} USB_DEVICE_DESCRIPTOR, *PUSB_DEVICE_DESCRIPTOR;
成员 bLength
指定此描述符的长度（以字节为单位）。 bDescriptorType
指定描述符类型。 必须设置为 USB_DEVICE_DESCRIPTOR_TYPE。 bcdUSB
标识此描述符结构符合的 USB 规范的版本。 此值是二进制编码的十进制数。 bDeviceClass
指定由 USB 规范组分配的设备类代码。 bDeviceSubClass
根据 USB 规范组分配的设备子类代码。 bDeviceProtocol
指定由 USB 规范组分配的设备协议代码。 bMaxPacketSize0
指定设备终结点零的最大数据包大小（以字节为单位）。 该值必须设置为 8、16、32 或 64。
idVendor
根据 USB 规范委员会分配的设备指定供应商标识符。 idProduct
指定产品标识符。 此值由制造商分配，特定于设备。 bcdDevice
标识设备的版本。 此值是二进制编码的十进制数。 iManufacturer
指定字符串描述符的设备定义索引，该索引提供包含此设备的制造商名称的字符串。 iProduct
指定字符串描述符的设备定义索引，该索引提供包含设备说明的字符串。 iSerialNumber
指定字符串描述符的设备定义索引，该索引提供一个字符串，其中包含设备的制造商确定序列号。
bNumConfigurations
指定设备的可能配置总数。

